# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        val textView = findViewById<TextView>(R.id.textView)

        if (intent.action == Intent.ACTION_SEND) {
            val type = intent.type
            when {
                "text/plain" == type -> handleText(intent.getStringExtra(Intent.EXTRA_TEXT))
                type?.startsWith("image/") == true -> handleImage(intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))
                else -> textView.text = "Unsupported share type"
            }
        } else {
            textView.text = "No data to share"
        }
    }

    private fun handleText(text: String?) {
        val textView = findViewById<TextView>(R.id.textView)
        text?.let {
            textView.text = it
        } ?: run {
            textView.text = "No text received"
        }
    }

    private fun handleImage(imageUri: Uri?) {
        val textView = findViewById<TextView>(R.id.textView)
        imageUri?.let {
            textView.text = "Image received: $imageUri"
        } ?: run {
            textView.text = "No image received"
        }
    }
}